/**
 * //property handling
 * $w.log("id:" + options.id);
 * $w.log("style:" + options.style);
 * $w.log("class:" + options.class);
 * $w.log("ref:" + options.ref);
 *
 * //event trigger
*/
// 초기 수행함수 
this.initMainCbnNtrlt = function() {
	// fill 설정
	/*
	var color = "";
	if (options.fill && options.fill != "") {
		color = options.fill;
	} else {
		color = "url(#" + grpMainBackArrowLlinearPaint.getID() + ")";
	}
	document.getElementById(grpMainBackArrowFill.getID()).setAttribute("fill", color);
	*/

	// 기본 설정
	var mainCbnNtrltFilter1Url = "url(#" + grpMainCbnNtrltFilter1.getID() + ")";
	var mainCbnNtrltFilter2Url = "url(#" + grpMainCbnNtrltFilter2.getID() + ")";
	var mainCbnNtrltGradialUrl = "url(#" + grpMainCbnNtrltGradial.getID() + ")";
	var mainCbnNtrltPatternUrl = "url(#" + grpMainCbnNtrltPattern.getID() + ")";
	var mainCbnNtrltLinear1Url = "url(#" + grpMainCbnNtrltLinear1.getID() + ")";
	var mainCbnNtrltLinear2Url = "url(#" + grpMainCbnNtrltLinear2.getID() + ")";
	var mainCbnNtrltClipPathUrl = "url(#" + grpMainCbnNtrltClipPath.getID() + ")";

	document.getElementById(grpGFilter1.getID()).setAttribute("filter", mainCbnNtrltFilter1Url);
	document.getElementById(grpPathGradial1.getID()).setAttribute("fill", mainCbnNtrltGradialUrl);
	document.getElementById(grpEllipseLinear1.getID()).setAttribute("fill", mainCbnNtrltLinear1Url);
	document.getElementById(grpRectPattern.getID()).setAttribute("fill", mainCbnNtrltPatternUrl);
	document.getElementById(grpPathLinear2.getID()).setAttribute("fill", mainCbnNtrltLinear2Url);
	document.getElementById(grpGFilter2.getID()).setAttribute("filter", mainCbnNtrltFilter2Url);
	document.getElementById(grpGFilter3.getID()).setAttribute("clip-path", mainCbnNtrltClipPathUrl);
};

// 초기 실행함수 수행
this.initMainCbnNtrlt();
